export function lookupMCC(code: string): string | undefined {
  return fullMCCReference[code];
}

export function suggestMCC(query: string): Array<{ code: string; description: string }> {
  if (!query || query.length < 2) return [];
  const q = query.toLowerCase();
  return Object.entries(fullMCCReference)
    .filter(([code, desc]) => code.includes(q) || desc.toLowerCase().includes(q))
    .slice(0, 10)
    .map(([code, description]) => ({ code, description }));
}
